1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	import { getConfig } from '../config/appConfig.js';
16	import defaultReputationService from './ReputationService.js';
17	
18	// Transitions only reviewers/admins may perform
19	const REVIEWER_ONLY_TRANSITIONS = [
20	  REGISTRATION_STATUS.UNDER_REVIEW,
21	  REGISTRATION_STATUS.APPROVED,
22	  REGISTRATION_STATUS.REJECTED,
23	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
24	  REGISTRATION_STATUS.WAITLISTED,
25	];
26	
27	export class RegistrationService {
28	  constructor(deps = {}) {
29	    this._registrationRepo = deps.registrationRepository || registrationRepository;
30	    this._eventRepo = deps.registrationEventRepository || registrationEventRepository;
31	    this._classRepo = deps.classRepository || classRepository;
32	    this._userRepo = deps.userRepository || userRepository;
33	    this._auditService = deps.auditService || defaultAuditService;
34	    this._reputationService = deps.reputationService || defaultReputationService;
35	  }
36	
37	  async create(userId, classId, notes = '') {
38	    if (!userId) throw new Error('userId is required to create a registration.');
39	    if (!classId) throw new Error('classId is required to create a registration.');
40	
41	    // Validate class exists and is available for registration
42	    const cls = await this._classRepo.getById(classId);
43	    if (!cls) throw new Error('Class not found. Cannot create registration for unknown class.');
44	    if (cls.status === 'completed') throw new Error('Cannot register for a completed class.');
45	    if (cls.capacity) {
46	      const existing = await this._registrationRepo.getByClassId(classId);
47	      const approvedCount = existing.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
48	      if (approvedCount >= cls.capacity) throw new Error('This class is at full capacity. No spots available.');
49	    }
50	
51	    // Reputation enforcement at service level per original prompt:
52	    // "a reputation score below 60 blocks new order-taking/booking privileges"
53	    const restricted = await this._reputationService.isRestricted(userId);
54	    if (restricted) {
55	      throw new Error('Registration blocked: your reputation score is below the minimum threshold. Contact an administrator for assistance.');
56	    }
57	
58	    const registration = createRegistration({
59	      id: generateId(),
60	      userId,
61	      classId,
62	      status: REGISTRATION_STATUS.DRAFT,
63	      notes,
64	    });
65	    await this._registrationRepo.add(registration);
66	    await this._logEvent(registration.id, null, registration.status, 'Registration created', userId);
67	    await this._auditService.log('registration', registration.id, 'created', `Registration created in ${registration.status}`, userId);
68	    eventBus.emit('registration:created', registration);
69	    return registration;
70	  }
71	
72	  async transition(registrationId, newStatus, comment, userId) {
73	    if (!registrationId) throw new Error('registrationId is required.');
74	    if (!newStatus) throw new Error('newStatus is required.');
75	    if (!userId) throw new Error('userId is required for transition.');
76	
77	    const reg = await this._registrationRepo.getById(registrationId);
78	    if (!reg) throw new Error('Registration not found.');
79	
80	    if (!canTransition(reg.status, newStatus)) {
81	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
82	    }
83	
84	    const actingUser = await this._userRepo.getById(userId);
85	    if (!actingUser) {
86	      throw new Error('Acting user not found. Cannot perform transition.');
87	    }
88	
89	    const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
90	    const isOwner = reg.userId === userId;
91	
92	    if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
93	      throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
94	    }
95	
96	    if (!isReviewerOrAdmin) {
97	      if (!isOwner) {
98	        throw new Error('You can only modify your own registrations.');
99	      }
100	      const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
101	      if (!selfAllowed.includes(newStatus)) {
102	        throw new Error(`You do not have permission to transition to ${newStatus}.`);
103	      }
104	    }
105	
106	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
107	      const config = getConfig();
108	      const minLen = (config.registration && config.registration.rejectionCommentMinLength) || 20;
109	      if (!comment || comment.trim().length < minLen) {
110	        throw new Error(`Rejection comment must be at least ${minLen} characters.`);
111	      }
112	    }
113	
114	    const fromStatus = reg.status;
115	    reg.status = newStatus;
116	    reg.updatedAt = now();
117	    await this._registrationRepo.put(reg);
118	
119	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
120	    await this._auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
121	
122	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
123	
124	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
125	      await this._checkWaitlistPromotion(reg.classId, userId);
126	    }
127	
128	    return reg;
129	  }
130	
131	  async batchTransition(registrationIds, newStatus, comment, userId) {
132	    const results = [];
133	    for (const id of registrationIds) {
134	      try {
135	        const reg = await this.transition(id, newStatus, comment, userId);
136	        results.push({ id, success: true, registration: reg });
137	      } catch (err) {
138	        results.push({ id, success: false, error: err.message });
139	      }
140	    }
141	    return results;
142	  }
143	
144	  async getById(registrationId) {
145	    return this._registrationRepo.getById(registrationId);
146	  }
147	
148	  async getAll() {
149	    return this._registrationRepo.getAll();
150	  }
151	
152	  /**
153	   * Get registrations scoped by the acting user's role.
154	   * Learner: own records only. Reviewer/Admin: all records.
155	   */
156	  async getAllScoped(actingUserId) {
157	    if (!actingUserId) return [];
158	    const user = await this._userRepo.getById(actingUserId);
159	    if (!user) return [];
160	    if ([USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role)) {
161	      return this._registrationRepo.getAll();
162	    }
163	    return this._registrationRepo.getByUserId(actingUserId);
164	  }
165	
166	  async getByUserId(userId) {
167	    return this._registrationRepo.getByUserId(userId);
168	  }
169	
170	  async getByStatus(status) {
171	    return this._registrationRepo.getByStatus(status);
172	  }
173	
174	  /**
175	   * Get registrations by status, scoped by the acting user's role.
176	   */
177	  async getByStatusScoped(status, actingUserId) {
178	    if (!actingUserId) return [];
179	    const user = await this._userRepo.getById(actingUserId);
180	    if (!user) return [];
181	    const all = await this._registrationRepo.getByStatus(status);
182	    if ([USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role)) {
183	      return all;
184	    }
185	    return all.filter(r => r.userId === actingUserId);
186	  }
187	
188	  async getByClassId(classId) {
189	    return this._registrationRepo.getByClassId(classId);
190	  }
191	
192	  async getEvents(registrationId) {
193	    return this._eventRepo.getByRegistrationId(registrationId);
194	  }
195	
196	  async getClassFillRate(classId) {
197	    if (!classId) return 0;
198	    const cls = await this._classRepo.getById(classId);
199	    if (!cls || !cls.capacity) return 0;
200	
201	    const regs = await this._registrationRepo.getByClassId(classId);
202	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
203	    return approvedCount / cls.capacity;
204	  }
205	
206	  async _checkWaitlistPromotion(classId, userId) {
207	    if (!classId) return;
208	
209	    const fillRate = await this.getClassFillRate(classId);
210	    const config = getConfig();
211	    const threshold = (config.registration && config.registration.waitlistPromotionFillRate) || 0.95;
212	    if (fillRate >= threshold) return;
213	
214	    const waitlisted = await this._registrationRepo.filter(
215	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
216	    );
217	    if (waitlisted.length === 0) return;
218	
219	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
220	
221	    const next = waitlisted[0];
222	    const fromStatus = next.status;
223	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
224	    next.updatedAt = now();
225	    await this._registrationRepo.put(next);
226	
227	    await this._logEvent(next.id, fromStatus, REGISTRATION_STATUS.UNDER_REVIEW, 'Auto-promoted from waitlist (seat available, fill rate < 95%)', userId);
228	    await this._auditService.log('registration', next.id, 'status_change', `${fromStatus} → ${REGISTRATION_STATUS.UNDER_REVIEW}: Waitlist promotion`, userId);
229	
230	    eventBus.emit('registration:transition', { registration: next, fromStatus, toStatus: REGISTRATION_STATUS.UNDER_REVIEW });
231	  }
232	
233	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
234	    const event = createRegistrationEvent({
235	      id: generateId(),
236	      registrationId,
237	      fromStatus,
238	      toStatus,
239	      comment,
240	      userId,
241	      timestamp: now(),
242	    });
243	    await this._eventRepo.add(event);
244	    return event;
245	  }
246	}
247	
248	export default new RegistrationService();
249	
