1	/**
2	 * RegistrationsPage — registration queue with filters, batch actions, and detail drawer.
3	 * Full implementation: class selection, status transitions in drawer, reputation enforcement.
4	 */
5	
6	import registrationService from '../services/RegistrationService.js';
7	import reputationService from '../services/ReputationService.js';
8	import authService from '../services/AuthService.js';
9	import auditService from '../services/AuditService.js';
10	import classRepository from '../repositories/ClassRepository.js';
11	import userRepository from '../repositories/UserRepository.js';
12	import DataTable from '../components/DataTable.js';
13	import Drawer from '../components/Drawer.js';
14	import AuditTimeline from '../components/AuditTimeline.js';
15	import Modal from '../components/Modal.js';
16	import Toast from '../components/Toast.js';
17	import { REGISTRATION_STATUS, getTransitions, getTerminalStates } from '../models/Registration.js';
18	import { USER_ROLES } from '../models/User.js';
19	import { escapeHtml, formatDate, maskId } from '../utils/helpers.js';
20	
21	export class RegistrationsPage {
22	  constructor(appShell) {
23	    this.appShell = appShell;
24	    this.table = null;
25	    this.currentFilter = '';
26	    this._submitting = false;
27	  }
28	
29	  async render() {
30	    this.appShell.setPageTitle('Registrations');
31	    const container = this.appShell.getContentContainer();
32	    const user = authService.getCurrentUser();
33	    const isReviewer = user && [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role);
34	
35	    const statusOptions = Object.values(REGISTRATION_STATUS).map(s =>
36	      `<option value="${s}">${s}</option>`
37	    ).join('');
38	
39	    container.innerHTML = `
40	      <div class="filters-bar">
41	        <select id="filter-status" class="form-control">
42	          <option value="">All Statuses</option>
43	          ${statusOptions}
44	        </select>
45	        <button class="btn btn-primary" id="btn-new-reg">+ New Registration</button>
46	        ${isReviewer ? `
47	          <button class="btn btn-secondary" id="btn-batch-approve">Batch Approve</button>
48	          <button class="btn btn-danger btn-sm" id="btn-batch-reject">Batch Reject</button>
49	        ` : ''}
50	      </div>
51	      <div id="registrations-table"></div>
52	    `;
53	
54	    await this._loadTable(container);
55	
56	    container.querySelector('#filter-status').addEventListener('change', async (e) => {
57	      this.currentFilter = e.target.value;
58	      await this._loadTable(container);
59	    });
60	
61	    container.querySelector('#btn-new-reg').addEventListener('click', () => {
62	      this._createRegistration();
63	    });
64	
65	    if (isReviewer) {
66	      container.querySelector('#btn-batch-approve').addEventListener('click', async () => {
67	        if (this._submitting) return;
68	        const ids = this.table.getSelectedIds();
69	        if (ids.length === 0) { Toast.warning('Select registrations first.'); return; }
70	        const confirmed = await Modal.confirm('Batch Approve', `Approve ${ids.length} registration(s)?`);
71	        if (!confirmed) return;
72	        this._submitting = true;
73	        try {
74	          const results = await registrationService.batchTransition(ids, REGISTRATION_STATUS.APPROVED, '', user.id);
75	          const succeeded = results.filter(r => r.success).length;
76	          Toast.success(`${succeeded} of ${ids.length} approved.`);
77	          await this._loadTable(container);
78	        } finally { this._submitting = false; }
79	      });
80	
81	      container.querySelector('#btn-batch-reject').addEventListener('click', async () => {
82	        const ids = this.table.getSelectedIds();
83	        if (ids.length === 0) { Toast.warning('Select registrations first.'); return; }
84	        this._batchRejectModal(ids);
85	      });
86	    }
87	  }
88	
89	  async _loadTable(container) {
90	    const user = authService.getCurrentUser();
91	    let data;
92	    if (this.currentFilter) {
93	      data = await registrationService.getByStatusScoped(this.currentFilter, user?.id);
94	    } else {
95	      data = await registrationService.getAllScoped(user?.id);
96	    }
97	
98	    data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
99	
100	    // Resolve user display names
101	    const userCache = {};
102	    const resolveUser = async (userId) => {
103	      if (!userId) return 'N/A';
104	      if (userCache[userId]) return userCache[userId];
105	      const u = await userRepository.getById(userId);
106	      userCache[userId] = u ? (u.displayName || u.username) : maskId(userId);
107	      return userCache[userId];
108	    };
109	    for (const reg of data) {
110	      reg._userName = await resolveUser(reg.userId);
111	    }
112	
113	    this.table = new DataTable({
114	      columns: [
115	        { key: 'id', label: 'ID', render: (r) => escapeHtml(maskId(r.id)) },
116	        { key: 'userId', label: 'User', render: (r) => escapeHtml(r._userName) },
117	        { key: 'classId', label: 'Class', render: (r) => r.classId ? escapeHtml(maskId(r.classId)) : '<em>None</em>' },
118	        { key: 'status', label: 'Status', render: (r) => `<span class="badge badge-${r.status.toLowerCase()}">${escapeHtml(r.status)}</span>` },
119	        { key: 'createdAt', label: 'Created', render: (r) => formatDate(r.createdAt) },
120	        { key: 'updatedAt', label: 'Updated', render: (r) => formatDate(r.updatedAt) },
121	      ],
122	      data,
123	      selectable: true,
124	      onRowClick: (row) => this._openDetail(row),
125	    });
126	
127	    this.table.render(container.querySelector('#registrations-table'));
128	  }
129	
130	  async _openDetail(registration) {
131	    // Refresh from DB
132	    registration = await registrationService.getById(registration.id) || registration;
133	    const auditLogs = await auditService.getTimeline(registration.id);
134	    const user = authService.getCurrentUser();
135	    const isTerminal = getTerminalStates().includes(registration.status);
136	    const isReviewer = user && [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role);
137	
138	    // Build allowed transitions for current status
139	    const allowedTransitions = getTransitions()[registration.status] || [];
140	
141	    // Build transition buttons
142	    let transitionHTML = '';
143	    if (!isTerminal && allowedTransitions.length > 0) {
144	      const isOwner = registration.userId === user?.id;
145	      // Learners can only cancel or submit
146	      const learnerAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
147	
148	      transitionHTML = `
149	        <hr style="margin:16px 0;border:none;border-top:1px solid var(--color-border)">
150	        <h3 style="margin-bottom:12px">Actions</h3>
151	        <div class="form-group">
152	          <label for="transition-comment">Comment</label>
153	          <textarea id="transition-comment" class="form-control" rows="2" placeholder="Comment (required for rejection, 20+ chars)"></textarea>
154	        </div>
155	        <div class="btn-group" style="flex-wrap:wrap">
156	          ${allowedTransitions.map(status => {
157	            if (!isReviewer && !learnerAllowed.includes(status)) return '';
158	            const btnClass = status === REGISTRATION_STATUS.APPROVED ? 'btn-primary' :
159	                             status === REGISTRATION_STATUS.REJECTED ? 'btn-danger' :
160	                             status === REGISTRATION_STATUS.CANCELLED ? 'btn-danger' : 'btn-secondary';
161	            return `<button class="btn btn-sm ${btnClass} transition-btn" data-status="${status}">${escapeHtml(status)}</button>`;
162	          }).join('')}
163	        </div>
164	        <div id="transition-error" class="form-error mt-4"></div>
165	      `;
166	    }
167	
168	    Drawer.open('Registration Detail', `
169	      <div class="form-group">
170	        <label>ID</label>
171	        <p>${escapeHtml(maskId(registration.id))}</p>
172	      </div>
173	      <div class="form-group">
174	        <label>Status</label>
175	        <p><span class="badge badge-${registration.status.toLowerCase()}">${escapeHtml(registration.status)}</span></p>
176	      </div>
177	      <div class="form-group">
178	        <label>User</label>
179	        <p>${escapeHtml(maskId(registration.userId))}</p>
180	      </div>
181	      <div class="form-group">
182	        <label>Class</label>
183	        <p>${registration.classId ? escapeHtml(maskId(registration.classId)) : '<em>Not assigned</em>'}</p>
184	      </div>
185	      <div class="form-group">
186	        <label>Notes</label>
187	        <p>${escapeHtml(registration.notes || 'None')}</p>
188	      </div>
189	      <div class="form-group">
190	        <label>Created</label>
191	        <p>${formatDate(registration.createdAt)}</p>
192	      </div>
193	      ${transitionHTML}
194	      <hr style="margin:16px 0;border:none;border-top:1px solid var(--color-border)">
195	      <h3 style="margin-bottom:12px">Audit Timeline</h3>
196	      <div id="drawer-audit-timeline"></div>
197	    `, (drawerEl) => {
198	      AuditTimeline.render(drawerEl.querySelector('#drawer-audit-timeline'), auditLogs);
199	
200	      // Wire transition buttons
201	      drawerEl.querySelectorAll('.transition-btn').forEach(btn => {
202	        btn.addEventListener('click', async () => {
203	          if (btn.disabled) return;
204	          const newStatus = btn.dataset.status;
205	          const comment = drawerEl.querySelector('#transition-comment')?.value || '';
206	          const errorEl = drawerEl.querySelector('#transition-error');
207	          errorEl.textContent = '';
208	          btn.disabled = true;
209	
210	          try {
211	            await registrationService.transition(registration.id, newStatus, comment, user.id);
212	            Toast.success(`Status changed to ${newStatus}.`);
213	            Drawer.closeAll();
214	            const container = this.appShell.getContentContainer();
215	            await this._loadTable(container);
216	          } catch (err) {
217	            errorEl.textContent = err.message;
218	            btn.disabled = false;
219	          }
220	        });
221	      });
222	    });
223	  }
224	
225	  async _createRegistration() {
226	    const user = authService.getCurrentUser();
227	    if (!user) return;
228	
229	    // UX guard: early rejection for restricted users (service layer is authoritative)
230	    const restricted = await reputationService.isRestricted(user.id);
231	    if (restricted) {
232	      Toast.error('Registration blocked: your reputation score is below the minimum threshold. Contact an administrator for assistance.');
233	      return;
234	    }
235	
236	    // Load classes for selection
237	    const classes = await classRepository.getAll();
238	
239	    const classOptions = classes.length > 0
240	      ? classes.map(c => `<option value="${c.id}">${escapeHtml(c.title || c.id)}</option>`).join('')
241	      : '<option value="">No classes available</option>';
242	
243	    Modal.custom('New Registration', `
244	      <form id="new-reg-form">
245	        <div class="form-group">
246	          <label for="reg-class">Class <span style="color:var(--color-danger)">*</span></label>
247	          <select id="reg-class" class="form-control" required>
248	            <option value="">-- Select a Class --</option>
249	            ${classOptions}
250	          </select>
251	        </div>
252	        <div class="form-group">
253	          <label for="reg-notes">Notes</label>
254	          <textarea id="reg-notes" class="form-control" rows="3" placeholder="Optional notes..."></textarea>
255	        </div>
256	        <div id="reg-error" class="form-error"></div>
257	        <button type="submit" class="btn btn-primary mt-4">Create Draft</button>
258	      </form>
259	    `, (modalEl, close) => {
260	      modalEl.querySelector('#new-reg-form').addEventListener('submit', async (e) => {
261	        e.preventDefault();
262	        try {
263	          const classId = modalEl.querySelector('#reg-class').value;
264	          const notes = modalEl.querySelector('#reg-notes').value;
265	          if (!classId) {
266	            modalEl.querySelector('#reg-error').textContent = 'Please select a class.';
267	            return;
268	          }
269	          const created = await registrationService.create(user.id, classId, notes);
270	          Toast.success('Draft registration created.');
271	          close();
272	          const container = this.appShell.getContentContainer();
273	          await this._loadTable(container);
274	        } catch (err) {
275	          modalEl.querySelector('#reg-error').textContent = err.message;
276	        }
277	      });
278	    });
279	  }
280	
281	  _batchRejectModal(ids) {
282	    Modal.custom('Batch Reject', `
283	      <form id="batch-reject-form">
284	        <p>Rejecting ${ids.length} registration(s). A comment of at least 20 characters is required.</p>
285	        <div class="form-group mt-4">
286	          <label for="br-comment">Rejection Comment</label>
287	          <textarea id="br-comment" class="form-control" rows="3" required minlength="20"></textarea>
288	          <small id="br-charcount" style="color:var(--color-text-muted)">0 / 20 min</small>
289	        </div>
290	        <div id="br-error" class="form-error"></div>
291	        <button type="submit" class="btn btn-danger mt-4">Reject All</button>
292	      </form>
293	    `, (modalEl, close) => {
294	      const textarea = modalEl.querySelector('#br-comment');
295	      const charcount = modalEl.querySelector('#br-charcount');
296	      textarea.addEventListener('input', () => {
297	        charcount.textContent = `${textarea.value.length} / 20 min`;
298	      });
