1	/**
2	 * Minimal static file server for the TrainingOps SPA.
3	 * No external dependencies — uses only Node.js built-ins.
4	 * Serves the project root so that public/index.html can reference ../src/ paths.
5	 */
6	
7	import { createServer } from 'node:http';
8	import { readFile, stat } from 'node:fs/promises';
9	import { join, extname } from 'node:path';
10	import { fileURLToPath } from 'node:url';
11	
12	const __dirname = fileURLToPath(new URL('.', import.meta.url));
13	const PORT = process.env.PORT || 8080;
14	
15	const MIME_TYPES = {
16	  '.html': 'text/html; charset=utf-8',
17	  '.css':  'text/css; charset=utf-8',
18	  '.js':   'application/javascript; charset=utf-8',
19	  '.json': 'application/json; charset=utf-8',
20	  '.png':  'image/png',
21	  '.jpg':  'image/jpeg',
22	  '.jpeg': 'image/jpeg',
23	  '.svg':  'image/svg+xml',
24	  '.ico':  'image/x-icon',
25	};
26	
27	const server = createServer(async (req, res) => {
28	  try {
29	    let urlPath = decodeURIComponent(new URL(req.url, `http://localhost`).pathname);
30	
31	    // Default route → serve public/index.html
32	    if (urlPath === '/' || urlPath === '') {
33	      urlPath = '/public/index.html';
34	    }
35	
36	    const filePath = join(__dirname, urlPath);
37	
38	    // Security: prevent directory traversal
39	    if (!filePath.startsWith(__dirname)) {
40	      res.writeHead(403);
41	      res.end('Forbidden');
42	      return;
43	    }
44	
45	    // Check file exists
46	    try {
47	      const fileStat = await stat(filePath);
48	      if (fileStat.isDirectory()) {
49	        // Try index.html in directory
50	        const indexPath = join(filePath, 'index.html');
51	        const content = await readFile(indexPath);
52	        res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
53	        res.end(content);
54	        return;
55	      }
56	    } catch {
57	      // For SPA hash-based routing, serve index.html for HTML requests
58	      if (!extname(urlPath)) {
59	        const content = await readFile(join(__dirname, 'public', 'index.html'));
60	        res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
61	        res.end(content);
62	        return;
63	      }
64	      res.writeHead(404);
65	      res.end('Not Found');
66	      return;
67	    }
68	
69	    const content = await readFile(filePath);
70	    const ext = extname(filePath).toLowerCase();
71	    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
72	
73	    // Prevent browsers from serving stale JS/CSS from cache after code updates
74	    const headers = { 'Content-Type': contentType };
75	    if (ext === '.js' || ext === '.css' || ext === '.json') {
76	      headers['Cache-Control'] = 'no-store';
77	    }
78	
79	    res.writeHead(200, headers);
80	    res.end(content);
81	  } catch (err) {
82	    console.error(`Error serving ${req.url}:`, err.message);
83	    res.writeHead(500);
84	    res.end('Internal Server Error');
85	  }
86	});
87	
88	server.listen(PORT, '0.0.0.0', () => {
89	  console.log(`TrainingOps server running at http://0.0.0.0:${PORT}`);
90	  console.log(`Open http://localhost:${PORT} in your browser`);
91	});
