1	/**
2	 * Registration domain model and state machine.
3	 * Transitions are loaded from config at runtime; hardcoded values are fallback only.
4	 */
5	
6	import { getConfig } from '../config/appConfig.js';
7	
8	export const REGISTRATION_STATUS = {
9	  DRAFT: 'Draft',
10	  SUBMITTED: 'Submitted',
11	  NEEDS_MORE_INFO: 'NeedsMoreInfo',
12	  UNDER_REVIEW: 'UnderReview',
13	  APPROVED: 'Approved',
14	  REJECTED: 'Rejected',
15	  CANCELLED: 'Cancelled',
16	  WAITLISTED: 'Waitlisted',
17	};
18	
19	/**
20	 * Fallback state transitions (used if config not loaded yet).
21	 */
22	const FALLBACK_TRANSITIONS = {
23	  [REGISTRATION_STATUS.DRAFT]:           [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED],
24	  [REGISTRATION_STATUS.SUBMITTED]:       [REGISTRATION_STATUS.NEEDS_MORE_INFO, REGISTRATION_STATUS.UNDER_REVIEW, REGISTRATION_STATUS.CANCELLED, REGISTRATION_STATUS.WAITLISTED],
25	  [REGISTRATION_STATUS.NEEDS_MORE_INFO]: [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED],
26	  [REGISTRATION_STATUS.UNDER_REVIEW]:    [REGISTRATION_STATUS.APPROVED, REGISTRATION_STATUS.REJECTED, REGISTRATION_STATUS.NEEDS_MORE_INFO, REGISTRATION_STATUS.CANCELLED],
27	  [REGISTRATION_STATUS.WAITLISTED]:      [REGISTRATION_STATUS.UNDER_REVIEW, REGISTRATION_STATUS.CANCELLED],
28	  [REGISTRATION_STATUS.APPROVED]:        [REGISTRATION_STATUS.CANCELLED],
29	  [REGISTRATION_STATUS.REJECTED]:        [],
30	  [REGISTRATION_STATUS.CANCELLED]:       [],
31	};
32	
33	const FALLBACK_TERMINAL = [REGISTRATION_STATUS.REJECTED, REGISTRATION_STATUS.CANCELLED];
34	
35	/**
36	 * Get the current transitions map, preferring config values.
37	 */
38	export function getTransitions() {
39	  const config = getConfig();
40	  if (config.registration && config.registration.transitions) {
41	    return config.registration.transitions;
42	  }
43	  return FALLBACK_TRANSITIONS;
44	}
45	
46	/**
47	 * Get terminal states from config or fallback.
48	 */
49	export function getTerminalStates() {
50	  const config = getConfig();
51	  if (config.registration && config.registration.terminalStates) {
52	    return config.registration.terminalStates;
53	  }
54	  return FALLBACK_TERMINAL;
55	}
56	
57	// Legacy exports for backward compatibility with existing code
58	export const REGISTRATION_TRANSITIONS = FALLBACK_TRANSITIONS;
59	export const TERMINAL_STATES = FALLBACK_TERMINAL;
60	
61	export function canTransition(fromStatus, toStatus) {
62	  const transitions = getTransitions();
63	  const allowed = transitions[fromStatus];
64	  return allowed ? allowed.includes(toStatus) : false;
65	}
66	
67	export function createRegistration({ id, userId, classId, status, notes = '', createdAt, updatedAt }) {
68	  return {
69	    id,
70	    userId,
71	    classId,
72	    status: status || REGISTRATION_STATUS.DRAFT,
73	    notes,
74	    createdAt: createdAt || new Date().toISOString(),
75	    updatedAt: updatedAt || new Date().toISOString(),
76	  };
77	}
78	
79	export function createRegistrationEvent({ id, registrationId, fromStatus, toStatus, comment = '', userId, timestamp }) {
80	  return {
81	    id,
82	    registrationId,
83	    fromStatus,
84	    toStatus,
85	    comment,
86	    userId,
87	    timestamp: timestamp || new Date().toISOString(),
88	  };
89	}
