1	/**
2	 * ReputationService — score calculation with 90-day rolling window,
3	 * threshold enforcement, and config-driven weights.
4	 */
5	
6	import reputationScoreRepository from '../repositories/ReputationScoreRepository.js';
7	import registrationRepository from '../repositories/RegistrationRepository.js';
8	import auditService from './AuditService.js';
9	import { createReputationScore, REPUTATION_THRESHOLD } from '../models/ReputationScore.js';
10	import { REGISTRATION_STATUS } from '../models/Registration.js';
11	import { generateId, now } from '../utils/helpers.js';
12	import { getConfig } from '../config/appConfig.js';
13	
14	const DEFAULT_WEIGHTS = {
15	  fulfillmentRate: 0.5,
16	  lateRate: 0.3,
17	  complaintRate: 0.2,
18	};
19	
20	export class ReputationService {
21	  constructor(deps = {}) {
22	    this._reputationScoreRepo = deps.reputationScoreRepository || reputationScoreRepository;
23	    this._registrationRepo = deps.registrationRepository || registrationRepository;
24	    this._auditService = deps.auditService || auditService;
25	  }
26	
27	  /**
28	   * Compute reputation from actual registration history within the configured window.
29	   * Uses real fulfillment, late, and complaint rates from historical data.
30	   */
31	  async computeScoreFromHistory(userId) {
32	    if (!userId) throw new Error('userId is required.');
33	
34	    const config = getConfig();
35	    const windowDays = (config.reputation && config.reputation.windowDays) || 90;
36	    const weights = (config.reputation && config.reputation.weights) || DEFAULT_WEIGHTS;
37	
38	    const cutoff = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000).toISOString();
39	
40	    // Get all registrations for user within the window (exclude future-dated)
41	    const allRegs = await this._registrationRepo.getByUserId(userId);
42	    const nowStr = new Date().toISOString();
43	    const windowRegs = allRegs.filter(r => r.createdAt >= cutoff && r.createdAt <= nowStr);
44	
45	    if (windowRegs.length === 0) {
46	      // No history in window — not restricted
47	      return null;
48	    }
49	
50	    const total = windowRegs.length;
51	    const approved = windowRegs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
52	    const rejected = windowRegs.filter(r => r.status === REGISTRATION_STATUS.REJECTED).length;
53	    const cancelled = windowRegs.filter(r => r.status === REGISTRATION_STATUS.CANCELLED).length;
54	
55	    const fulfillmentRate = total > 0 ? approved / total : 1;
56	    // Late rate: cancelled after approval counts as "late" (failed to attend)
57	    const lateRate = total > 0 ? cancelled / total : 0;
58	    const complaintRate = total > 0 ? rejected / total : 0;
59	
60	    return this.computeScore(userId, { fulfillmentRate, lateRate, complaintRate }, weights);
61	  }
62	
63	  /**
64	   * Compute and store reputation score for a user from provided metrics.
65	   * @param {string} userId
66	   * @param {object} metrics — { fulfillmentRate: 0–1, lateRate: 0–1, complaintRate: 0–1 }
67	   * @param {object} [weights] — optional custom weights
68	   */
69	  async computeScore(userId, metrics, weights) {
70	    if (!weights) {
71	      const config = getConfig();
72	      weights = (config.reputation && config.reputation.weights) || DEFAULT_WEIGHTS;
73	    }
74	    if (!userId) throw new Error('userId is required.');
75	    if (!metrics) throw new Error('metrics object is required.');
76	
77	    const validate01 = (v, name) => {
78	      const n = Number(v);
79	      if (isNaN(n) || n < 0 || n > 1) throw new Error(`${name} must be between 0 and 1.`);
80	      return n;
81	    };
82	    metrics.fulfillmentRate = validate01(metrics.fulfillmentRate, 'fulfillmentRate');
83	    metrics.lateRate = validate01(metrics.lateRate, 'lateRate');
84	    metrics.complaintRate = validate01(metrics.complaintRate, 'complaintRate');
85	
86	    const score = Math.round(
87	      (metrics.fulfillmentRate * weights.fulfillmentRate +
88	        (1 - metrics.lateRate) * weights.lateRate +
89	        (1 - metrics.complaintRate) * weights.complaintRate) * 100
90	    );
91	
92	    const clampedScore = Math.max(0, Math.min(100, score));
93	
94	    const existing = await this.getScore(userId);
95	
96	    const record = createReputationScore({
97	      id: existing ? existing.id : generateId(),
98	      userId,
99	      score: clampedScore,
100	      fulfillmentRate: metrics.fulfillmentRate,
101	      lateRate: metrics.lateRate,
102	      complaintRate: metrics.complaintRate,
103	    });
104	
105	    await this._reputationScoreRepo.put(record);
106	    await this._auditService.log('reputation', userId, 'computed', `Score: ${clampedScore}`, 'system');
107	
108	    return record;
109	  }
110	
111	  /**
112	   * Get the current reputation score for a user.
113	   */
114	  async getScore(userId) {
115	    const results = await this._reputationScoreRepo.getByUserId(userId);
116	    if (Array.isArray(results)) return results[0] || null;
117	    return results;
118	  }
119	
120	  /**
121	   * Check if user is below threshold and should be restricted.
122	   */
123	  async isRestricted(userId) {
124	    const record = await this.getScore(userId);
125	    if (!record) return false; // no score computed yet, not restricted
126	    const config = getConfig();
127	    const threshold = (config.reputation && config.reputation.threshold) || REPUTATION_THRESHOLD;
128	    return record.score < threshold;
129	  }
130	
131	  /**
132	   * Get all reputation scores.
133	   */
134	  async getAllScores() {
135	    return this._reputationScoreRepo.getAll();
136	  }
137	}
138	
139	export default new ReputationService();
