      }
      console.warn(`Port ${port} in use, trying next port ${nextPort}...`);
      server.removeListener('error', onError);
      startServer(nextPort, attempt + 1);
    } else {
      console.error(`Server error: ${err.message}`);
      process.exit(1);
    }
  };

  server.on('error', onError);

