1	/**
2	 * Minimal static file server for the TrainingOps SPA.
3	 * No external dependencies — uses only Node.js built-ins.
4	 * Serves the project root so that public/index.html can reference ../src/ paths.
5	 */
6	
7	import { createServer } from 'node:http';
8	import { readFile, stat } from 'node:fs/promises';
9	import { join, extname } from 'node:path';
10	import { fileURLToPath } from 'node:url';
11	
12	const __dirname = fileURLToPath(new URL('.', import.meta.url));
13	const BASE_PORT = Number(process.env.PORT) || 8080;
14	const MAX_PORT_RETRIES = 5;
15	
16	const MIME_TYPES = {
17	  '.html': 'text/html; charset=utf-8',
18	  '.css':  'text/css; charset=utf-8',
19	  '.js':   'application/javascript; charset=utf-8',
20	  '.json': 'application/json; charset=utf-8',
21	  '.png':  'image/png',
22	  '.jpg':  'image/jpeg',
23	  '.jpeg': 'image/jpeg',
24	  '.svg':  'image/svg+xml',
25	  '.ico':  'image/x-icon',
26	};
27	
28	const server = createServer(async (req, res) => {
29	  try {
30	    let urlPath = decodeURIComponent(new URL(req.url, `http://localhost`).pathname);
31	
32	    // Default route → serve public/index.html
33	    if (urlPath === '/' || urlPath === '') {
34	      urlPath = '/public/index.html';
35	    }
36	
37	    const filePath = join(__dirname, urlPath);
38	
39	    // Security: prevent directory traversal
40	    if (!filePath.startsWith(__dirname)) {
41	      res.writeHead(403);
42	      res.end('Forbidden');
43	      return;
44	    }
45	
46	    // Check file exists
47	    try {
48	      const fileStat = await stat(filePath);
49	      if (fileStat.isDirectory()) {
50	        // Try index.html in directory
51	        const indexPath = join(filePath, 'index.html');
52	        const content = await readFile(indexPath);
53	        res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
54	        res.end(content);
55	        return;
56	      }
57	    } catch {
58	      // For SPA hash-based routing, serve index.html for HTML requests
59	      if (!extname(urlPath)) {
60	        const content = await readFile(join(__dirname, 'public', 'index.html'));
61	        res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
62	        res.end(content);
63	        return;
64	      }
65	      res.writeHead(404);
66	      res.end('Not Found');
67	      return;
68	    }
69	
70	    const content = await readFile(filePath);
71	    const ext = extname(filePath).toLowerCase();
72	    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
73	
74	    // Prevent browsers from serving stale JS/CSS from cache after code updates
75	    const headers = { 'Content-Type': contentType };
76	    if (ext === '.js' || ext === '.css' || ext === '.json') {
77	      headers['Cache-Control'] = 'no-store';
78	    }
79	
80	    res.writeHead(200, headers);
81	    res.end(content);
82	  } catch (err) {
83	    console.error(`Error serving ${req.url}:`, err.message);
84	    res.writeHead(500);
85	    res.end('Internal Server Error');
86	  }
87	});
88	
89	/**
90	 * Attempt to listen on BASE_PORT, retrying up to MAX_PORT_RETRIES on EADDRINUSE.
91	 */
92	function startServer(port, attempt) {
93	  // Register error handler BEFORE listen to avoid race conditions
94	  const onError = (err) => {
95	    if (err.code === 'EADDRINUSE') {
96	      const nextPort = port + 1;
97	      if (attempt >= MAX_PORT_RETRIES) {
98	        console.error(`All ports ${BASE_PORT}–${port} are in use. Exiting.`);
99	        process.exit(1);
100	      }
101	      console.warn(`Port ${port} in use, trying next port ${nextPort}...`);
102	      server.removeListener('error', onError);
103	      startServer(nextPort, attempt + 1);
104	    } else {
105	      console.error(`Server error: ${err.message}`);
106	      process.exit(1);
107	    }
108	  };
109	
110	  server.on('error', onError);
111	
112	  server.listen(port, '0.0.0.0', () => {
113	    // Only print success after confirmed listening — remove error handler for this attempt
114	    server.removeListener('error', onError);
115	    console.log(`TrainingOps server running at http://0.0.0.0:${port}`);
116	    console.log(`Open http://localhost:${port} in your browser`);
117	  });
